const formatVolNoTrailing = (val: number | undefined | null): string => {
  if (val === undefined || val === null || isNaN(val)) return '0';
  const fixed = val.toFixed(3);
  const parsed = parseFloat(fixed);
  return parsed.toString();
};

function generate52WeeksForYear(year: number): WeekInfo[] {
  const weeks: WeekInfo[] = [];
  // Find the first Monday of the year
  const jan1 = new Date(year, 0, 1);
  const day = jan1.getDay(); // Sunday=0, Monday=1, ...
  // Monday of the week containing Jan 1st
  const diff = jan1.getDate() - day + (day === 0 ? -6 : 1);
  const startMonday = new Date(year, 0, diff);
  
  const pad = (n: number) => String(n).padStart(2, '0');
  
  for (let w = 1; w <= 52; w++) {
    const monday = new Date(startMonday.getTime() + (w - 1) * 7 * 24 * 60 * 60 * 1000);
    const sunday = new Date(monday.getTime() + 6 * 24 * 60 * 60 * 1000);
    
    const startStr = `${pad(monday.getDate())}/${pad(monday.getMonth() + 1)}`;
    const endStr = `${pad(sunday.getDate())}/${pad(sunday.getMonth() + 1)}/${sunday.getFullYear()}`;
    
    weeks.push({
      weekNum: w,
      year: year,
      monday,
      sunday,
      weekId: `${year}-W${pad(w)}`,
      label: `Tuần ${w} / ${year} (${startStr} - ${endStr})`
    });
  }
  return weeks;
}

interface WeekInfo {
  weekNum: number;
  year: number;
  monday: Date;
  sunday: Date;
  weekId: string;
  label: string;
}

function getWeekInfo(dateStr: string): WeekInfo | null {
  try {
    if (!dateStr) return null;
    const parts = dateStr.trim().split('T')[0].split('-');
    if (parts.length < 3) return null;
    const d = new Date(parseInt(parts[0], 10), parseInt(parts[1], 10) - 1, parseInt(parts[2], 10));
    if (isNaN(d.getTime())) return null;

    // ISO-8601 week number calculation
    const target = new Date(d.valueOf());
    const dayNr = (d.getDay() + 6) % 7; // Monday = 0, Sunday = 6
    target.setDate(target.getDate() - dayNr + 3);
    const firstThursday = target.valueOf();
    target.setMonth(0, 1);
    if (target.getDay() !== 4) {
      target.setMonth(0, 1 + ((4 - target.getDay()) + 7) % 7);
    }
    const weekNum = 1 + Math.ceil((firstThursday - target.valueOf()) / 604800000);
    const year = new Date(firstThursday).getFullYear();

    // Monday & Sunday
    const monday = new Date(d.valueOf());
    monday.setDate(monday.getDate() - dayNr);
    const sunday = new Date(monday.valueOf());
    sunday.setDate(sunday.getDate() + 6);

    // Format week start & end dates
    const pad = (n: number) => String(n).padStart(2, '0');
    const startStr = `${pad(monday.getDate())}/${pad(monday.getMonth() + 1)}`;
    const endStr = `${pad(sunday.getDate())}/${pad(sunday.getMonth() + 1)}/${sunday.getFullYear()}`;

    return {
      weekNum,
      year,
      monday,
      sunday,
      weekId: `${year}-W${pad(weekNum)}`,
      label: `Tuần ${weekNum} / ${year} (${startStr} - ${endStr})`
    };
  } catch (err) {
    return null;
  }
}

const EXCLUDED_SUPPLIER_NAMES = [
  'HTX Lâm Nghiệp Yên Thế',
  'Hợp tác xã Lâm nghiệp Yên Thế',
  'Công ty TNHH MTV Đồng Tâm',
  'Doanh nghiệp tư nhân Hùng Phát'
];

const shouldExcludeSupplier = (name: string) => {
  if (!name) return false;
  const normalized = name.trim().toLowerCase();
  return EXCLUDED_SUPPLIER_NAMES.some(ex => ex.trim().toLowerCase() === normalized);
};

