  const handleImportExcelPaste = () => {
    if (!excelPasteText.trim()) {
      alert("Vui lòng dán dữ liệu từ file Excel vào ô nhập bốc đo!");
      return;
    }

    const parsedRows = parseExcelPaste(excelPasteText);
    if (parsedRows.length === 0) {
      alert("Không tìm thấy dữ liệu quy cách hợp lệ nào trong nội dung dán. Quy cách cần ghi dạng L x W x T hoặc chia cột!");
      return;
    }

    const newSizes: string[] = [];
    parsedRows.forEach(row => {
      const sizeStr = row.kich_thuoc_mm;
      if (sizeStr && !newSizes.includes(sizeStr) && !danhMucQuyCach.includes(sizeStr)) {
        newSizes.push(sizeStr);
      }
    });

    if (newSizes.length === 0) {
      alert("Tất cả các kích thước dán từ Excel đã tồn tại trong danh mục hàng hóa!");
      setExcelPasteText('');
      return;
    }

    setDanhMucQuyCach(prev => [...prev, ...newSizes]);

    alert(`Đã thêm thành công ${newSizes.length} quy cách gỗ mới vào danh mục hàng hóa!`);
    setExcelPasteText('');
  };

