  const handleRestoreData = (data: Record<string, string>, mode: 'merge' | 'overwrite') => {
    try {
      if (mode === 'overwrite') {
        // Clear old ones first
        backupKeys.forEach(bk => {
          localStorage.removeItem(bk.key);
        });

        // Set new ones
        Object.keys(data).forEach(key => {
          localStorage.setItem(key, data[key]);
        });
      } else {
        // Merge mode!
        Object.keys(data).forEach(key => {
          const oldVal = localStorage.getItem(key);
          const newVal = data[key];
          
          if (!oldVal) {
            // No old data, just set directly
            localStorage.setItem(key, newVal);
            return;
          }

          try {
            const oldParsed = JSON.parse(oldVal);
            const newParsed = JSON.parse(newVal);

            if (Array.isArray(oldParsed) && Array.isArray(newParsed)) {
              // It is an array of records! Merge by id to avoid duplicates
              const mergedMap = new Map<string, any>();
              
              // Load old
              oldParsed.forEach(item => {
                const id = item.id || JSON.stringify(item);
                mergedMap.set(id, item);
              });

              // Overwrite with new
              newParsed.forEach(item => {
                const id = item.id || JSON.stringify(item);
                mergedMap.set(id, item);
              });

              localStorage.setItem(key, JSON.stringify(Array.from(mergedMap.values())));
            } else if (typeof oldParsed === 'object' && oldParsed !== null && typeof newParsed === 'object' && newParsed !== null) {
              // It is an object/map! Merge key-value
              const mergedObj = { ...oldParsed, ...newParsed };
              localStorage.setItem(key, JSON.stringify(mergedObj));
            } else {
              // Non-mergables, default to overwrite with new
              localStorage.setItem(key, newVal);
            }
          } catch {
            // Failed to merge, overwrite with new
            localStorage.setItem(key, newVal);
          }
        });
      }

      alert("Khôi phục dữ liệu thành công! Ứng dụng sẽ tải lại trang để áp dụng cơ sở dữ liệu mới.");
      window.location.reload();
    } catch (err) {
      alert("Lỗi khi khôi phục dữ liệu: " + String(err));
    }
  };

