  const checkSectionPermission = (sectionId: string): boolean => {
    const userEmailLower = currentUser?.email?.toLowerCase();
    // Default system root email has absolute full security clearances
    if (userEmailLower === 'duc941980@gmail.com') {
      return true;
    }
    
    // Admin keyword check also grants absolute access to simplify administration
    const roleLower = (currentUser?.role || '').toLowerCase();
    if (roleLower.includes('admin') || roleLower.includes('quản trị') || roleLower.includes('quan tri')) {
      return true;
    }

    // Ưu tiên quyền đã tải cùng tài khoản đăng nhập.
    if (Array.isArray(currentUser?.permissions)) {
      return currentUser.permissions.includes(sectionId);
    }

    // Otherwise, check custom database record
    const rawUsers = localStorage.getItem('wood_users_db_v1');
    if (rawUsers) {
      try {
        const users = JSON.parse(rawUsers);
        const matched = users.find((u: any) => u.email?.toLowerCase() === userEmailLower);
        if (matched) {
          if (Array.isArray(matched.permissions)) {
            return matched.permissions.includes(sectionId);
          }
          return true; // Backward compatibility
        }
      } catch (e) {
        // Fallback
      }
    }
    return false;
  };
  
