  const handleDeleteSystemUser = (emailToDelete: string) => {
    const rawUsers = localStorage.getItem('wood_users_db_v1');
    let users = [];
    try {
      users = rawUsers ? JSON.parse(rawUsers) : [];
    } catch (e) {
      users = [];
    }
    
    // Prevent deleting the currently logged-in user
    if (currentUser && currentUser.email.toLowerCase() === emailToDelete.toLowerCase()) {
      alert('Không thể xóa tài khoản bạn đang sử dụng!');
      setUserToConfirmDelete(null);
      return;
    }

    // Prevent deleting default user (Phạm Anh Quân)
    const fallbackEmail = 'duc941980@gmail.com';
    if (emailToDelete.toLowerCase() === fallbackEmail.toLowerCase()) {
      alert('Không thể xóa tài khoản Quản trị mặc định!');
      setUserToConfirmDelete(null);
      return;
    }

    const updatedUsers = users.filter((u: any) => u.email.toLowerCase() !== emailToDelete.toLowerCase());
    localStorage.setItem('wood_users_db_v1', JSON.stringify(updatedUsers));
    
    setUserToConfirmDelete(null);
    loadSystemUsersList();
  };

  const handleSaveSystemUserEdit = (emailToEdit: string) => {
    if (!editFullName.trim() || !editUsername.trim() || !editRole.trim() || !editPassword.trim()) {
      alert("Vui lòng điền đầy đủ tất cả thông tin!");
      return;
    }

    const rawUsers = localStorage.getItem('wood_users_db_v1');
    let users = [];
    try {
      users = rawUsers ? JSON.parse(rawUsers) : [];
    } catch (e) {
      users = [];
    }

    const index = users.findIndex((u: any) => u.email.toLowerCase() === emailToEdit.toLowerCase());
    if (index >= 0) {
      const updatedUser = {
        ...users[index],
        fullName: editFullName.trim(),
        username: editUsername.trim().toLowerCase().replace(/\s+/g, ''),
        role: editRole.trim(),
        permissions: editPermissions,
        password: editPassword.trim()
      };
      
      users[index] = updatedUser;
      localStorage.setItem('wood_users_db_v1', JSON.stringify(users));

      // If active user edited themselves, call propagation logic
      if (currentUser && currentUser.email.toLowerCase() === emailToEdit.toLowerCase() && onUpdateUser) {
        onUpdateUser({
          ...currentUser,
          fullName: editFullName.trim(),
          username: editUsername.trim().toLowerCase().replace(/\s+/g, ''),
          role: editRole.trim()
        });
      }

      setEditingUserIndex(null);
      loadSystemUsersList();
    }
  };

