  const handleSendDebtChatMessage = async (customText?: string) => {
    const textToSend = (customText || debtChatInput).trim();
    if (!textToSend) return;

    if (!customText) {
      setDebtChatInput('');
    }

    const newUserMessage = { role: 'user' as const, content: textToSend };
    const updatedMessages = [...debtChatMessages, newUserMessage];
    setDebtChatMessages(updatedMessages);
    setDebtChatLoading(true);

    try {
      const response = await fetch('/api/chat-debt', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-gemini-key': geminiApiKey,
        },
        body: JSON.stringify({
          messages: updatedMessages,
          context: {
            selectedDebtWeek,
            summaryData: weeklyDebtSummary.map(s => ({
              supplierName: s.supplierName,
              startingBalance: s.startingBalance,
              periodVolume: s.periodVolume,
              periodPurchases: s.periodPurchases,
              periodPaid: s.periodPaid,
              endingBalance: s.endingBalance,
              recordsCountInPeriod: s.recordsCountInPeriod,
            })),
          }
        }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Lỗi không xác định từ máy chủ');
      }

      const data = await response.json();
      setDebtChatMessages(prev => [...prev, { role: 'assistant', content: data.text }]);
    } catch (error: any) {
      console.error("Chat Error:", error);
      setDebtChatMessages(prev => [
        ...prev,
        { 
          role: 'assistant', 
          content: `⚠️ **Lỗi kết nối hoặc xử lý**: ${error.message || 'Không thể kết nối tới máy chủ AI. Vui lòng thử lại!'}` 
        }
      ]);
    } finally {
      setDebtChatLoading(false);
    }
  };

