                          ketoanEnvFilter === 'fsc'
                            ? 'bg-[#1a5fb4] text-white shadow-3xs border-none'
                            : 'text-slate-600 hover:text-indigo-900 bg-white hover:bg-slate-50 border border-slate-200'
