                              const found = historyInspections.find(hb => hb.ma_bbnt === selectedSavedMaForDelete);
                              if (found) {
                                // Clean up any linked payment proposals, invoices, and payment logs completely
                                cleanupLinkedFinancials(found.ma_bbnt);

                                const resetRecord = {
                                  ...found,
                                  bang_thanh_toan: [],
                                  bang_duyet_gia: [],
                                  phat_sinh_chi_phi: [],
                                  da_luu_thanh_toan: false,
                                  trang_thai_thanh_toan: undefined
                                };
                                onSave(resetRecord, false);
                                if (id === found.id) {
                                  setBangThanhToan([]);
                                  setBangDuyetGia([]);
                                  setPhatSinhChiPhi([]);
                                  setExplicitlyLoadedForPayment(false);
                                  setLoadedBienBan(null);
                                  handleAddNewRecord();
                                }
                                setSelectedSavedMaForDelete('');
                                alert(`✓ Đã xóa dữ liệu quyết toán của biên bản ${found.ma_bbnt} thành công. Biên bản nghiệm thu QC thô và các chứng từ liên quan đã được xóa sạch.`);
                              }
                              setIsConfirmingMainDelete(false);
