interface InvoiceEditModalProps {
  invoice: Invoice;
  onClose: () => void;
  onSave: (updated: Invoice) => void;
}

function InvoiceEditModal({ invoice, onClose, onSave }: InvoiceEditModalProps) {
  const [invoiceNo, setInvoiceNo] = useState(invoice.invoiceNo);
  const [symbol, setSymbol] = useState(invoice.symbol);
  const [invoiceDate, setInvoiceDate] = useState(invoice.invoiceDate);
  const [supplierName, setSupplierName] = useState(invoice.supplierName);
  const [totalVolume, setTotalVolume] = useState(invoice.totalVolume.toString());
  const [amountBeforeTax, setAmountBeforeTax] = useState(invoice.amountBeforeTax.toString());
  const [taxRate, setTaxRate] = useState<number>(invoice.taxRate ?? 8);
  const [note, setNote] = useState(invoice.note || '');
  const [status, setStatus] = useState(invoice.status);

  const preTax = parseFloat(amountBeforeTax) || 0;
  const taxAmount = preTax * (taxRate / 100);
  const totalAmount = preTax + taxAmount;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...invoice,
      invoiceNo,
      symbol,
      invoiceDate,
      supplierName,
      totalVolume: parseFloat(totalVolume) || 0,
      amountBeforeTax: preTax,
      taxRate,
      taxAmount,
      totalAmount,
      status,
      note,
    });
  };

  return (
    <div className="fixed inset-0 bg-slate-950/60 flex items-center justify-center p-4 z-100 backdrop-blur-xs overflow-y-auto font-sans">
      <div className="bg-white border border-slate-200 rounded-2xl shadow-2xl max-w-2xl w-full p-6 space-y-4 max-h-[95vh] overflow-y-auto text-slate-900 text-left relative">
        <div className="flex justify-between items-center pb-3 border-b border-slate-150">
          <h3 className="text-sm font-black text-slate-950 uppercase tracking-wider flex items-center gap-2">
            <Edit className="w-5 h-5 text-amber-600 animate-pulse" />
            CHỈNH SỬA HÓA ĐƠN VAT
          </h3>
          <button type="button" onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-slate-650 transition cursor-pointer">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Số Biên bản QC <span className="text-rose-500">*</span></label>
              <input
                type="text"
                required
                value={invoiceNo}
                onChange={(e) => setInvoiceNo(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Số Hóa đơn <span className="text-rose-500">*</span></label>
              <input
                type="text"
                required
                value={symbol}
                onChange={(e) => setSymbol(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Ngày lập hóa đơn <span className="text-rose-500">*</span></label>
              <input
                type="date"
                required
                value={invoiceDate}
                onChange={(e) => setInvoiceDate(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Trạng thái hạch toán <span className="text-rose-500">*</span></label>
              <select
                value={status}
                onChange={(e) => setStatus(e.target.value as any)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs cursor-pointer"
              >
                <option value="Đã ký số">Đã ký số (Hoàn tất)</option>
                <option value="Chờ ký">Chờ ký</option>
                <option value="Hủy bỏ">Hủy bỏ</option>
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 gap-4">
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Nhà cung cấp <span className="text-rose-500">*</span></label>
              <input
                type="text"
                required
                value={supplierName}
                onChange={(e) => setSupplierName(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Khối lượng (m³) <span className="text-rose-500">*</span></label>
              <input
                type="number"
                step="0.001"
                required
                value={totalVolume}
                onChange={(e) => setTotalVolume(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Cộng tiền trước thuế (đ) <span className="text-rose-500">*</span></label>
              <input
                type="number"
                required
                value={amountBeforeTax}
                onChange={(e) => setAmountBeforeTax(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Thuế suất VAT (%)</label>
              <select
                value={taxRate}
                onChange={(e) => setTaxRate(Number(e.target.value))}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs cursor-pointer"
              >
                <option value="8">8%</option>
                <option value="10">10%</option>
                <option value="5">5%</option>
                <option value="0">0%</option>
              </select>
            </div>
          </div>

          <div className="bg-slate-50 border border-slate-200 p-3.5 rounded-xl space-y-1.5 text-xs">
            <div className="flex justify-between">
              <span className="text-slate-500 font-bold">Cộng tiền trước thuế:</span>
              <span className="font-mono font-bold text-slate-900">{preTax.toLocaleString('vi-VN')} đ</span>
            </div>
            <div className="flex justify-between">
              <span className="text-slate-500 font-bold">Tiền thuế VAT ({taxRate}%):</span>
              <span className="font-mono font-semibold text-slate-700">{taxAmount.toLocaleString('vi-VN')} đ</span>
            </div>
            <div className="flex justify-between border-t border-slate-200 pt-1.5 mt-1">
              <span className="text-slate-950 font-black">Tổng cộng tiền thanh toán:</span>
              <span className="font-mono font-black text-emerald-800">{totalAmount.toLocaleString('vi-VN')} đ</span>
            </div>
          </div>

          <div>
            <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Ghi chú hóa đơn</label>
            <input
              type="text"
              value={note}
              onChange={(e) => setNote(e.target.value)}
              className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
            />
          </div>

          <div className="flex justify-end gap-2 pt-3 border-t border-slate-150">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-650 rounded-xl text-xs font-bold transition cursor-pointer"
            >
              Hủy
            </button>
            <button
              type="submit"
              className="px-5 py-2 bg-emerald-650 hover:bg-emerald-700 text-white rounded-xl text-xs font-black shadow-md transition cursor-pointer flex items-center gap-1.5"
            >
              <CheckCircle className="w-4 h-4" />
              LƯU THAY ĐỔI
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

interface PaymentProposalEditModalProps {
  proposal: PaymentProposal;
  onClose: () => void;
  onSave: (updated: PaymentProposal) => void;
  translateMoneyToWords: (amount: number) => string;
  customSalesEmployeesList: string[];
}

function PaymentProposalEditModal({ proposal, onClose, onSave, translateMoneyToWords, customSalesEmployeesList }: PaymentProposalEditModalProps) {
  const [proposalNo, setProposalNo] = useState(proposal.proposalNo);
  const [proposalDate, setProposalDate] = useState(proposal.proposalDate);
  const [supplierName, setSupplierName] = useState(proposal.supplierName);
  const [bbntId, setBbntId] = useState(proposal.bbntId || '');
  const [invoiceId, setInvoiceId] = useState(proposal.invoiceId || '');
  const [amount, setAmount] = useState(proposal.amount.toString());
  const [paymentMethod, setPaymentMethod] = useState(proposal.paymentMethod);
  const [bankName, setBankName] = useState(proposal.bankName || '');
  const [bankAccountNo, setBankAccountNo] = useState(proposal.bankAccountNo || '');
  const [bankAccountName, setBankAccountName] = useState(proposal.bankAccountName || '');
  const [reason, setReason] = useState(proposal.reason);
  const [status, setStatus] = useState(proposal.status);
  const [requesterName, setRequesterName] = useState(proposal.requesterName);
  const [isCustomRequester, setIsCustomRequester] = useState(() => {
    return proposal.requesterName ? !customSalesEmployeesList.includes(proposal.requesterName) : false;
  });
  const [notes, setNotes] = useState(proposal.notes || '');
  const [totalVolume, setTotalVolume] = useState(proposal.totalVolume?.toString() || '');

  const numericAmount = parseFloat(amount) || 0;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      ...proposal,
      proposalNo,
      proposalDate,
      supplierName,
      bbntId: bbntId ? bbntId : undefined,
      invoiceId: invoiceId ? invoiceId : undefined,
      amount: numericAmount,
      paymentMethod,
      bankName: paymentMethod === 'Chuyển khoản' ? bankName : undefined,
      bankAccountNo: paymentMethod === 'Chuyển khoản' ? bankAccountNo : undefined,
      bankAccountName: paymentMethod === 'Chuyển khoản' ? bankAccountName : undefined,
      reason,
      status,
      requesterName,
      notes: notes ? notes : undefined,
      totalVolume: totalVolume ? parseFloat(totalVolume) : undefined
    });
  };

  return (
    <div className="fixed inset-0 bg-slate-950/60 flex items-center justify-center p-4 z-100 backdrop-blur-xs overflow-y-auto font-sans">
      <div className="bg-white border border-slate-200 rounded-2xl shadow-2xl max-w-2xl w-full p-6 space-y-4 max-h-[95vh] overflow-y-auto text-slate-900 text-left relative">
        <div className="flex justify-between items-center pb-3 border-b border-slate-150">
          <h3 className="text-sm font-black text-slate-950 uppercase tracking-wider flex items-center gap-2">
            <Edit className="w-5 h-5 text-amber-600 animate-pulse" />
            CHỈNH SỬA PHIẾU ĐỀ NGHỊ THANH TOÁN
          </h3>
          <button type="button" onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-lg text-slate-400 hover:text-slate-650 transition cursor-pointer">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Số đề nghị <span className="text-rose-500">*</span></label>
              <input
                type="text"
                required
                value={proposalNo}
                onChange={(e) => setProposalNo(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Ngày lập đề nghị <span className="text-rose-500">*</span></label>
              <input
                type="date"
                required
                value={proposalDate}
                onChange={(e) => setProposalDate(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Nhà cung cấp <span className="text-rose-500">*</span></label>
              <input
                type="text"
                required
                value={supplierName}
                onChange={(e) => setSupplierName(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider flex justify-between items-center">
                <span>Người lập đề nghị <span className="text-rose-500">*</span></span>
                {isCustomRequester && (
                  <button
                    type="button"
                    onClick={() => {
                      setIsCustomRequester(false);
                      setRequesterName(customSalesEmployeesList[0] || '');
                    }}
                    className="text-[9px] text-sky-650 hover:underline font-extrabold cursor-pointer"
                  >
                    Quay lại chọn danh sách
                  </button>
                )}
              </label>
              {!isCustomRequester ? (
                <select
                  required
                  value={requesterName}
                  onChange={(e) => {
                    if (e.target.value === '__custom__') {
                      setIsCustomRequester(true);
                      setRequesterName('');
                    } else {
                      setRequesterName(e.target.value);
                    }
                  }}
                  className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs cursor-pointer"
                >
                  <option value="">-- Chọn Người lập đề nghị --</option>
                  {customSalesEmployeesList.map((emp) => (
                    <option key={emp} value={emp}>{emp}</option>
                  ))}
                  <option value="__custom__">✍️ Nhập tên nhân sự khác...</option>
                </select>
              ) : (
                <input
                  type="text"
                  required
                  value={requesterName}
                  onChange={(e) => setRequesterName(e.target.value)}
                  placeholder="Nhập họ và tên người lập..."
                  className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
                  autoFocus
                />
              )}
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Số Biên bản (nếu có)</label>
              <input
                type="text"
                value={bbntId}
                onChange={(e) => setBbntId(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs font-mono"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Mã hóa đơn liên kết</label>
              <input
                type="text"
                value={invoiceId}
                onChange={(e) => setInvoiceId(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs font-mono"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Khối lượng (m³)</label>
              <input
                type="number"
                step="0.001"
                value={totalVolume}
                onChange={(e) => setTotalVolume(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <div className="sm:col-span-2">
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Số tiền chi (VND) <span className="text-rose-500">*</span></label>
              <input
                type="number"
                required
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-mono font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Hình thức <span className="text-rose-500">*</span></label>
              <select
                value={paymentMethod}
                onChange={(e) => setPaymentMethod(e.target.value as any)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs cursor-pointer"
              >
                <option value="Chuyển khoản">Chuyển khoản</option>
                <option value="Tiền mặt">Tiền mặt</option>
              </select>
            </div>
          </div>

          {paymentMethod === 'Chuyển khoản' && (
            <div className="bg-slate-50 border border-slate-200 p-4 rounded-xl space-y-3 animate-fadeIn">
              <h4 className="text-[10px] font-black uppercase text-slate-600 tracking-wider">Thông tin tài khoản nhận tiền</h4>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                <div>
                  <label className="block text-[9px] uppercase font-bold text-slate-500 mb-1">Tên ngân hàng</label>
                  <input
                    type="text"
                    value={bankName}
                    onChange={(e) => setBankName(e.target.value)}
                    placeholder="Vietcombank..."
                    className="w-full bg-white border border-slate-250 rounded-lg px-2.5 py-1.5 text-xs font-bold text-slate-800"
                  />
                </div>
                <div>
                  <label className="block text-[9px] uppercase font-bold text-slate-500 mb-1">Số tài khoản</label>
                  <input
                    type="text"
                    value={bankAccountNo}
                    onChange={(e) => setBankAccountNo(e.target.value)}
                    placeholder="001100..."
                    className="w-full bg-white border border-slate-250 rounded-lg px-2.5 py-1.5 text-xs font-mono font-bold text-slate-800"
                  />
                </div>
                <div>
                  <label className="block text-[9px] uppercase font-bold text-slate-500 mb-1">Chủ tài khoản</label>
                  <input
                    type="text"
                    value={bankAccountName}
                    onChange={(e) => setBankAccountName(e.target.value)}
                    placeholder="CONG TY..."
                    className="w-full bg-white border border-slate-250 rounded-lg px-2.5 py-1.5 text-xs font-bold text-slate-800 uppercase"
                  />
                </div>
              </div>
            </div>
          )}

          {numericAmount > 0 && (
            <div className="text-[10px] text-emerald-800 font-bold leading-normal bg-emerald-50/70 border border-emerald-150 p-2.5 rounded-xl">
              Bằng chữ: <span className="font-black underline">{translateMoneyToWords(numericAmount)} ./.</span>
            </div>
          )}

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Trạng thái phê duyệt <span className="text-rose-500">*</span></label>
              <select
                value={status}
                onChange={(e) => setStatus(e.target.value as any)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs cursor-pointer"
              >
                <option value="Chưa thanh toán">⚠ Chưa thanh toán</option>
                <option value="Đã thanh toán">✓ Đã thanh toán</option>
              </select>
            </div>
            <div>
              <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Ghi chú kế toán</label>
              <input
                type="text"
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
                className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs"
              />
            </div>
          </div>

          <div>
            <label className="block text-[10px] uppercase font-black text-slate-500 mb-1 tracking-wider">Nội dung diễn giải chi tiết <span className="text-rose-500">*</span></label>
            <textarea
              required
              rows={3}
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              className="w-full bg-white border border-slate-300 rounded-lg px-3 py-2 text-xs font-bold text-slate-900 focus:ring-2 focus:ring-sky-500 focus:outline-hidden shadow-3xs resize-none"
            />
          </div>

          <div className="flex justify-end gap-2 pt-3 border-t border-slate-150">
            <button
              type="button"
              onClick={onClose}
              className="px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-650 rounded-xl text-xs font-bold transition cursor-pointer"
            >
              Hủy
            </button>
            <button
              type="submit"
              className="px-5 py-2 bg-emerald-650 hover:bg-emerald-700 text-white rounded-xl text-xs font-black shadow-md transition cursor-pointer flex items-center gap-1.5"
            >
              <CheckCircle className="w-4 h-4" />
              LƯU THAY ĐỔI
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
